import { gtEndpoint } from './endpoint';
import type { CostSheetFilter } from './models';

export const gtService = {
  getCostSheets: (f?: CostSheetFilter) => gtEndpoint.getCostSheets(f),
  getCostSheet: (id: string) => gtEndpoint.getCostSheet(id),
  getCostElements: (id: string) => gtEndpoint.getCostElements(id),
  calculateCosts: (month: number, year: number) => gtEndpoint.calculateCosts(month, year),
  approveCostSheet: (id: string) => gtEndpoint.approveCostSheet(id),
  postCostSheet: (id: string) => gtEndpoint.postCostSheet(id),
};
